import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const sqlRoot = path.resolve(__dirname, "..");
const migrationsRoot = path.resolve(__dirname, "../../migrations");

const MIGRATION_ORDER = [
  "0001_init",
  "0002_admin_inventory_fields",
  "0003_product_seo_fields",
  "0004_admin_auth_tables",
  "0005_content_management_cms",
  "0006_admin_order_management",
  "0007_admin_settings",
  "0008_seo_automation",
  "0009_copy_config",
  "0010_product_research",
  "0011_product_bilingual_fields",
  "0012_content_bilingual_fields",
  "0013_collection_landing_bilingual_intro",
  "0014_static_page_content",
  "0015_product_research_risk_resolution",
  "0016_inventory_reservation",
  "20260525011718_product_research",
];

const migrationsOutDir = path.join(sqlRoot, "migrations");
fs.mkdirSync(migrationsOutDir, { recursive: true });

const combined = [
  "-- PulseGear incremental migrations (combined)",
  "-- Generated by prisma/sql/scripts/build-sql-bundle.mjs",
  "-- Prefer 01_full_schema.sql for fresh databases.",
  "",
];

for (const [index, folder] of MIGRATION_ORDER.entries()) {
  const sourcePath = path.join(migrationsRoot, folder, "migration.sql");
  if (!fs.existsSync(sourcePath)) {
    throw new Error(`Missing migration: ${folder}`);
  }
  const sql = fs.readFileSync(sourcePath, "utf8").trim();
  const targetName = `${String(index + 1).padStart(2, "0")}_${folder}.sql`;
  fs.writeFileSync(path.join(migrationsOutDir, targetName), `${sql}\n`, "utf8");
  combined.push(`-- >>> ${folder}`);
  combined.push(sql);
  combined.push("");
}

fs.writeFileSync(path.join(sqlRoot, "02_migrations_combined.sql"), `${combined.join("\n")}\n`, "utf8");
console.log(`Wrote ${MIGRATION_ORDER.length} files to prisma/sql/migrations/`);
console.log("Wrote prisma/sql/02_migrations_combined.sql");
